            aWandererA = aWandererA ^ ((RotL64(aScatter, 23U) + aOrbiterG) + RotL64(aOrbiterD, 39U));
            aWandererK = aWandererK + (((RotL64(aCross, 29U) + aOrbiterG) + RotL64(aOrbiterB, 43U)) + RotL64(aCarry, 53U));
