            //
            aOrbiterF = (aWandererD + RotL64(aPrevious, 29U)) + 0x8FE98FE5DA55D703ULL;
            aOrbiterG = (aWandererF + RotL64(aIngress, 43U)) + 0x6A05A8C1C37B9C10ULL;
            aOrbiterA = (aWandererJ + RotL64(aCross, 34U)) + 0x103D73DB58195786ULL;
