            //
            aOrbiterE = (aOrbiterE + aOrbiterD) + 0x15F5386A68A5A164ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0xD3A756D3164C9E56ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x58BD1FC22BCE312BULL), 21U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterA) + 0x1EEE90A7C68910BBULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterB) ^ 0x5D86D096E3012A16ULL;
            aOrbiterI = RotL64((aOrbiterI * 0xC93E9AFC69D08AB7ULL), 27U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterF) + 0x51211588DBAFA50CULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterC) ^ 0x05B291B8B27CCD86ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x4849ED0C0E369F65ULL), 23U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 0xB36D9B0469BA630AULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0xECD49D92AED44A30ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xD46897AFC5D25E51ULL), 51U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterH) + 0xC5861ADD269C593CULL) + aPhaseGOrbiterUpdateSaltB[(((31U - aIndex) + 11U)) & 31];
            aOrbiterE = ((aOrbiterE ^ aOrbiterA) ^ 0x59A0426AB76EC78CULL) ^ aPhaseGOrbiterUpdateSaltC[((aIndex + 25U)) & 31];
            aOrbiterE = RotL64((aOrbiterE * 0x6565045CE49A5B5BULL), 3U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterK) + 0xCCA93E9A3468276CULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0xC80D076F6F59160CULL;
